public class ETG_VendAccountStatementIntUIBuilder extends SrsReportDataContractUIBuilder
{
    ETG_VendAccountStatementIntContract contract;
    public DialogField  financialDimensions;
    public DialogField  financialDimSet;
    public DialogField  withoutTrans;

}

Method.Source:
public void postBuild()
{
    DialogField dialogField;

    super();

    contract = this.dataContractObject();
    contract.parmBankLCImportEnable(BankLCImportFeatureChecker::checkBankLCImportEnabled());

    // after framework has built all fields, enable/disable the dialogfield for BankLCBankDocumentType
    dialogField = this.bindInfo().getDialogField(contract, methodStr(ETG_VendAccountStatementIntContract, parmBankLCBankDocumentType));

    if (dialogField && !contract.parmBankLCImportEnable())
    {
        dialogField.visible(false);
    }

    dialogField = this.bindInfo().getDialogField(contract, methodstr(ETG_VendAccountStatementIntContract, parmSPaySchedule));

    if (dialogField && isConfigurationkeyEnabled(configurationKeyNum(PublicSector)))
    {
        dialogField.label(literalstr("@SPS1703"));
    }
    else if (dialogField)
    {
        dialogField.label(literalstr("@SYS67749"));
    }

    financialDimensions = this.bindInfo().getDialogField(contract, methodStr(ETG_VendAccountStatementIntContract, parmFinancialDimensions));
    financialDimensions.registerOverrideMethod(methodStr(FormCheckBoxControl, modified), methodStr(ETG_VendAccountStatementIntUIBuilder, financialDimensionsModified), this);
    financialDimSet = this.bindInfo().getDialogField(contract, methodStr(ETG_VendAccountStatementIntContract, parmFinancialDimSet));
    withoutTrans = this.bindInfo().getDialogField(contract, methodStr(CustAccountStatementIntContract, parmWithoutTrans));
    withoutTrans.registerOverrideMethod(methodStr(FormCheckBoxControl, modified), methodStr(ETG_CustAccountStatementIntUIBuilder_Extension, withoutTransModified), this);
}

public boolean financialDimensionsModified(FormCheckBoxControl _control)
{
    if (_control.modified())
    {
        if (_control.value() == 1)
        {
            financialDimSet.enabled(true);
        }
        else
        {
            financialDimSet.enabled(false);
            financialDimSet.value("");
            contract.parmFinancialDimSet("");
        }
    }

    return  true;
}

public boolean withoutTransModified(FormCheckBoxControl _control)
{
    if (_control.modified())
    {
        if (_control.value() == 1)
        {
            financialDimensions.value(0);
            contract.parmFinancialDimensions(0);
            financialDimensions.enabled(false);
            financialDimSet.enabled(false);
            financialDimSet.value("");
            contract.parmFinancialDimSet("");
        }
        else
        {
            financialDimensions.enabled(true);
            if (financialDimensions.value() == 1)
            {
                financialDimSet.enabled(true);
            }
            else
            {
                financialDimSet.enabled(false);
                financialDimSet.value("");
                contract.parmFinancialDimSet("");
            }
        }
    }

    return  true;
}

/// <summary>
///    creating dimension sets lookup
/// </summary>
/// <param name = "_formStringControl">form string control</param>
public void finDimSetLookup(FormStringControl   _formStringControl)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tablenum(DimensionHierarchy), _formStringControl);

    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Name));
    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Description));

    qbds = query.addDataSource(tableNum(DimensionHierarchy));
    qbds.addRange(fieldNum(DimensionHierarchy, StructureType)).value(queryValue(DimensionHierarchyType::Focus));
    qbds.addRange(fieldNum(DimensionHierarchy, IsSystemGenerated)).value(queryValue(NoYes::No));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
///
/// </summary>
public void build()
{
    super();
    contract = this.dataContractObject();
    financialDimensions = this.bindInfo().getDialogField(contract, methodStr(CustAccountStatementIntContract, parmFinancialDimensions));
    financialDimSet     = this.addDialogField(methodstr(CustAccountStatementIntContract, parmFinancialDimSet), contract);
    withoutTrans        = this.bindInfo().getDialogField(contract, methodStr(CustAccountStatementIntContract, parmWithoutTrans));
    if (withoutTrans.value() == 1)
    {
        financialDimensions.value(0);
        contract.parmFinancialDimensions(0);
        financialDimensions.enabled(false);
    }
    else
    {
        financialDimensions.enabled(true);
    }

    if (financialDimensions.value() == 1)
    {
        financialDimSet.enabled(true);
    }
    else
    {
        financialDimSet.enabled(false);
        financialDimSet.value("");
        contract.parmFinancialDimSet("");
    }
}
